import akka.actor.ActorSystem
import akka.http.scaladsl.Http
import akka.http.scaladsl.model._
import akka.http.scaladsl.server.Directives._
import akka.stream.ActorMaterializer
import scala.concurrent.{ExecutionContext, Future}
import scala.util.{Failure, Success}

object WebhookProxyService {
  implicit val system: ActorSystem = ActorSystem("WebhookProxyService")
  implicit val materializer: ActorMaterializer = ActorMaterializer()
  implicit val executionContext: ExecutionContext = system.dispatcher

  val route =
    path("fetch") {
      post {
        entity(as[String]) { urlString =>
          if (urlString.trim.isEmpty) {
            complete(StatusCodes.BadRequest, "URL cannot be empty")
          } else {
            val uri = Uri(urlString)

            if (!uri.isAbsolute) {
              complete(StatusCodes.BadRequest, "Provided string is not an absolute URL")
            } else {
              val responseFuture: Future[HttpResponse] = Http().singleRequest(HttpRequest(uri = uri))

              onComplete(responseFuture) {
                case Success(clientResponse) =>
                  // Forward the status code and the entity from the client response
                  complete(clientResponse.status, clientResponse.entity)
                case Failure(ex) =>
                  // Log the exception for debugging
                  system.log.error(ex, s"Failed to fetch content from URL: $urlString")
                  complete(StatusCodes.InternalServerError, s"Failed to fetch URL: ${ex.getMessage}")
              }
            }
          }
        }
      }
    }

  def main(args: Array[String]): Unit = {
    val bindingFuture = Http().bindAndHandle(route, "0.0.0.0", 8080)

    println(s"Server online at http://0.0.0.0:8080/\nPress RETURN to stop...")
    scala.io.StdIn.readLine() // let it run until user presses return
